tmpls.afmt:
{{#Title}}
<div style="opacity: 0.7">
  Article:
  <b>
    {{#Cloze title?}} {{cloze:Title}} {{/Cloze title?}} {{^Cloze title?}}
    {{Title}} {{/Cloze title?}}
  </b>
</div>
<br />
{{/Title}}

<div id="cloze-root">{{cloze:Extract}}</div>
<br />
<div>{{type:cloze:Extract}}</div>
<br />

<div style="opacity: 0.7; font-size: 80%">{{Back Extra}}</div>

<div id="context">
  {{#Link}}
  <a href="{{text:Link}}">{{Context}}</a>
  {{/Link}} {{^Link}} {{Context}} {{/Link}}
</div>

<script>
  (function () {
    const root = document.getElementById("cloze-root");
    if (!root) return;

    root.innerHTML = root.innerHTML.replace(
      /\[\[c(\d+)::([^\]]+?)(?:::([^\]]+))?\]\]/g,
      (_, n, text, hint) =>
        `<span data-hide-for="${n}" ${hint ? `data-hint="${hint}"` : ""}>${text}</span>`,
    );

    const active = root.querySelector(".cloze:not(.cloze-inactive)");
    if (!active) return;

    const activeOrdinal = active.getAttribute("data-ordinal");
    if (!activeOrdinal) return;

    root
      .querySelectorAll(`[data-hide-for="${activeOrdinal}"]`)
      .forEach((el) => {
        el.classList.add("hidden-untested");
      });
  })();
</script>

tmpls.qfmt:
{{#Title}}
<div style="opacity: 0.7">
  Article:
  <b>
    {{#Cloze title?}} {{cloze:Title}} {{/Cloze title?}} {{^Cloze title?}}
    {{Title}} {{/Cloze title?}}
  </b>
</div>
<br />
{{/Title}}

<div id="cloze-root">{{cloze:Extract}}</div>

<script>
  setTimeout(function () {
    const normalise = (s) =>
      s
        .replace(/<[^>]*>/g, " ")
        .replace(/&nbsp;/gi, " ")
        .replace(/\s+/g, " ")
        .trim();

    const escapeHtml = (s) =>
      s.replace(
        /[&<>"']/g,
        (ch) =>
          ({
            "&": "&amp;",
            "<": "&lt;",
            ">": "&gt;",
            '"': "&quot;",
            "'": "&#39;",
          })[ch],
      );

    function focusCurrent() {
      if (current >= queue.length) return;
      const item = queue[current];
      if (!item || !item.input || item.input.disabled) return;

      item.input.focus();
      item.input.select();

      if (document.activeElement !== item.input) {
        setTimeout(() => {
          item.input.focus();
          item.input.select();
        }, 30);
      }
    }

    function compareAnswer(typed, expected) {
      const a = normalise(typed);
      const b = normalise(expected);
      return a === b;
    }

    function markCorrect(item) {
      item.wrapper.classList.remove("is-wrong");
      item.wrapper.classList.add("is-correct");
      item.feedback.textContent = "";
      item.input.value = item.answer;
      item.input.disabled = true;
      current += 1;
      syncMirrors(item, true);
      focusCurrent();
    }

    function markWrong(item) {
      item.wrapper.classList.remove("is-correct");
      item.wrapper.classList.add("is-wrong");
      item.feedback.textContent = " ✗ ";
      item.input.blur();
    }

    const root = document.getElementById("cloze-root");
    if (!root) return;

    // get current active cloze ordinal
    const active = root.querySelector(".cloze[data-ordinal][data-cloze]");
    if (!active) return;

    const activeOrdinal = active.getAttribute("data-ordinal");
    if (!activeOrdinal) return;

    // replace "fake" cloze syntax with "fake" cloze elements
    root.innerHTML = root.innerHTML.replace(
      /\[\[c(\d+)::([^\]]+?)(?:::([^\]]+))?\]\]/g,
      (_, n, text, hint) =>
        `<span class="fake-cloze" data-hide-for="${n}" data-answer="${escapeHtml(text)}" ${hint ? `data-hint="${escapeHtml(hint)}"` : ""}>${escapeHtml(text)}</span>`,
    );

    // format "fake" clozes
    const fakeTargets = Array.from(
      root.querySelectorAll(`.fake-cloze[data-hide-for="${activeOrdinal}"]`),
    );

    const realTargets = Array.from(
      root.querySelectorAll(
        `.cloze[data-ordinal="${activeOrdinal}"][data-cloze]`,
      ),
    );

    if (!realTargets.length) return;

    const queue = [];

    // replace "real" clozes with input fields
    realTargets.forEach((el, index) => {
      const answer = el.getAttribute("data-cloze");
      const wrapper = document.createElement("span");
      const hint =
        el.textContent.slice(1, -1) === "..."
          ? null
          : el.textContent.slice(1, -1);
      wrapper.className = "typed-cloze-wrapper";
      wrapper.dataset.index = String(index);

      wrapper.innerHTML = `
      <input class="typed-cloze-input tappable" type="text" autocomplete="off" autocorrect="off" autocapitalize="off" spellcheck="false" placeholder="${el.textContent}">
      <span class="typed-cloze-measure" aria-hidden="true">...</span>
      <span class="typed-cloze-feedback"></span>
    `;

      el.replaceWith(wrapper);

      queue.push({
        wrapper,
        input: wrapper.querySelector(".typed-cloze-input"),
        measure: wrapper.querySelector(".typed-cloze-measure"),
        feedback: wrapper.querySelector(".typed-cloze-feedback"),
        placeholder: el.textContent,
        hint,
        answer,
        mirrors: [],
      });
    });

    console.log(queue);

    fakeTargets.forEach((el) => {
      const hint = el.getAttribute("data-hint");
      const owner =
        hint && hint !== "..."
          ? queue.find((item) => item.hint === hint)
          : null;

      if (!owner) {
        el.textContent = hint == null ? "[...]" : "[" + hint + "]";
        el.classList.add("hidden-untested");
      } else {
        el.innerHTML = `<span class="linked-fake-value">[${hint}]</span>`;
        el.classList.add("hidden-untested", "linked-fake-cloze");
        owner.mirrors.push({
          answer: el.getAttribute("data-answer") || "",
          cloze: el.querySelector(".linked-fake-value"),
        });
      }
    });

    let current = 0;

    const syncInputWidth = (item) => {
      item.measure.textContent = item.input.value || item.placeholder;
      item.input.style.width = item.measure.offsetWidth + "px";
    };

    const syncMirrors = (item, final = false) => {
      const text =
        item.input.value ||
        (item.hint == null ? "[...]" : "[" + item.hint + "]");
      item.mirrors.forEach((mirror) => {
        mirror.cloze.textContent = final ? mirror.answer : text;
      });
    };

    // add event listeners to the "real" clozes
    queue.forEach((item, index) => {
      if (index !== 0) item.input.disabled = true;
      syncInputWidth(item);
      syncMirrors(item);

      item.input.addEventListener("keydown", (ev) => {
        if (ev.key !== "Enter") return;

        ev.preventDefault();

        if (index !== current) return;

        if (compareAnswer(item.input.value, item.answer)) {
          markCorrect(item);
          if (current < queue.length) {
            queue[current].input.disabled = false;
            focusCurrent();
          }
        } else {
          markWrong(item);
        }
      });

      item.input.addEventListener("focus", () => {
        item.wrapper.classList.remove("is-wrong");
        item.feedback.textContent = "";
      });

      item.input.addEventListener("input", () => {
        syncInputWidth(item);
        syncMirrors(item);
        item.wrapper.classList.remove("is-wrong");
        item.feedback.textContent = "";
      });
    });

    document.addEventListener("keydown", (ev) => {
      if (
        ev.key !== "Backspace" ||
        document.activeElement.classList.contains("typed-cloze-input")
      )
        return;

      ev.preventDefault();
      focusCurrent();
    });

    requestAnimationFrame(() => {
      console.log("Focusing first cloze input");
      setTimeout(focusCurrent, 20);
    });
  }, 25);
</script>

